#include <stdio.h>
#include <string.h>
#define MOD 1000000007
#define MAXN 500
long long fact[MAXN + 1];
long long invFact[MAXN + 1];
long long modPow(long long a, long long e) {
    long long r = 1;
    while (e) {
        if (e & 1) r = r * a % MOD;
        a = a * a % MOD;
        e >>= 1;
    }
    return r;
}
void precompute() {
    fact[0] = 1;
    for (int i = 1; i <= MAXN; ++i) fact[i] = fact[i - 1] * i % MOD;
    invFact[MAXN] = modPow(fact[MAXN], MOD - 2);
    for (int i = MAXN; i > 0; --i) invFact[i - 1] = invFact[i] * i % MOD;
}
int main() {
    precompute();
    int T; 
    if (scanf("%d", &T) != 1) return 0;
    char s[MAXN + 5];
    while (T--) {
        scanf("%s", s);
        int freq[256] = {0};
        int n = strlen(s);
        for (int i = 0; i < n; ++i) freq[(unsigned char)s[i]]++;
        long long ans = fact[n];
        for (int i = 0; i < 256; ++i) if (freq[i]) ans = ans * invFact[freq[i]] % MOD;
        printf("%lld\n", ans);
    }
    return 0;
}

